exercises.solution_code:
#include <iostream>

enum Day
{
    Monday,
    Tuesday,
    Wednesday,
    Thursday,
    Friday
};

int main()
{
    int input{};
    std::cin >> input;

    if (input < 0 || input > 4)
    {
        std::cout << "Invalid day" << '\n';
        return 0;
    }

    Day day{ static_cast<Day>(input) };

    std::cout << "Day " << day << " selected" << '\n';

    return 0;
}

