exercises.solution_code:
#include <iostream>

enum Action
{
    Miss = 0,
    Hit = 1,
    CriticalHit = 2
};

int scoreValue(Action a)
{
    return a;
}

int main()
{
    int n{};
    std::cin >> n;

    int totalScore{ 0 };
    int hitCount{ 0 };

    for (int i{ 0 }; i < n; ++i)
    {
        int code{};
        std::cin >> code;

        Action action{ static_cast<Action>(code) };

        totalScore += scoreValue(action);

        if (action != Miss)
            ++hitCount;
    }

    std::cout << "Hits: " << hitCount << '\n';
    std::cout << "Score: " << totalScore << '\n';

    return 0;
}
